solution_code:
#include <iostream>

class Rectangle {
public:
    constexpr Rectangle(int w, int h) : m_w{w}, m_h{h} {}
    constexpr int area() const { return m_w * m_h; }
private:
    int m_w, m_h;
};

static_assert(Rectangle{3, 4}.area() == 12, "area must be 12");

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int w, h;
        std::cin >> w >> h;
        Rectangle r{w, h};
        std::cout << "area=" << r.area() << "\n";
    }
}

