solution_code:
#include <iostream>

struct Color {
    int r, g, b;
};

constexpr Color blend(Color a, Color b) {
    return Color{(a.r + b.r) / 2, (a.g + b.g) / 2, (a.b + b.b) / 2};
}

static_assert(blend(Color{0, 0, 0}, Color{100, 200, 50}).g == 100,
              "blend g-component must be 100");

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int r1, g1, b1, r2, g2, b2;
        std::cin >> r1 >> g1 >> b1 >> r2 >> g2 >> b2;
        Color c = blend(Color{r1, g1, b1}, Color{r2, g2, b2});
        std::cout << "(" << c.r << "," << c.g << "," << c.b << ")\n";
    }
}
